// VitePress build-time data loader for the benchmarks page.
//
// The canonical source of truth is `benchmarks/results.json`,
// regenerated by `mise run bench:bump` (which runs
// `benchmarks/bench.sh` and writes the JSON via
// `benchmarks/generate-results.js`). This loader re-reads that file
// during every dev-mode rebuild and inlines it into the bundle for
// production builds, so the chart on `/benchmarks` always matches
// the committed JSON and never drifts inside the markdown itself.
//
// Schema (see `benchmarks/generate-results.js`):
//   {
//     updated: string (ISO timestamp),
//     unit: "ms",
//     managers: string[],                      // e.g. ["pnpm", "aube"]
//     rows: [
//       {
//         key: string,                         // stable identifier, matches bench.sh scenario names
//         label: string,                       // human-readable column label
//         values: { [manager]: number | null } // mean in `unit`
//         stats?: { [manager]: { mean, stddev, min, max, text } | null }
//       },
//       ...
//     ],
//   }
//
// `defineLoader`'s `watch` glob triggers a hot reload whenever the
// committed JSON changes — drop a new `benchmarks/results.json` on
// disk and `aube docs:dev` updates the chart without a restart.

import fs from 'node:fs'
import path from 'node:path'
import { fileURLToPath } from 'node:url'

// ESM-compatible equivalent of CJS `__dirname`. VitePress runs this
// loader through esbuild/Node in ESM mode, so `__dirname` isn't
// available and we resolve against `import.meta.url` instead.
const __dirname = path.dirname(fileURLToPath(import.meta.url))
const JSON_PATH = path.resolve(__dirname, '../benchmarks/results.json')

export interface BenchRow {
  key: string
  label: string
  values: Record<string, number | null>
}

export interface BenchData {
  updated: string
  unit: string
  managers: string[]
  versions: Record<string, string>
  rows: BenchRow[]
}

declare const data: BenchData
export { data }

export default {
  // Relative glob so VitePress re-runs `load` on hot changes in dev
  // mode whenever `benchmarks/results.json` is rewritten (e.g. by
  // `mise run bench:bump`).
  watch: ['../benchmarks/results.json'],
  load(): BenchData {
    const raw = fs.readFileSync(JSON_PATH, 'utf8')
    const parsed = JSON.parse(raw) as BenchData
    return {
      updated: parsed.updated,
      unit: parsed.unit,
      managers: parsed.managers,
      versions: parsed.versions ?? {},
      rows: parsed.rows.map((r) => ({
        key: r.key,
        label: r.label,
        values: r.values,
      })),
    }
  },
}
